// build.gradle: implementation 'org.springframework.kafka:spring-kafka:3.2.4'

// application.yaml:
// spring:
//   kafka:
//     bootstrap-servers: kafka-1:9092,kafka-2:9092,kafka-3:9092
//     producer:
//       key-serializer: org.apache.kafka.common.serialization.StringSerializer
//       value-serializer: org.springframework.kafka.support.serializer.JsonSerializer
//       properties:
//         acks: all                # wait for leader + all in-sync replicas
//         enable.idempotence: true # deduplicate producer retries
//         retries: 10
//     consumer:
//       group-id: billing-service
//       key-deserializer: org.apache.kafka.common.serialization.StringDeserializer
//       value-deserializer: org.springframework.kafka.support.serializer.JsonDeserializer
//       auto-offset-reset: earliest
//       enable-auto-commit: false   # manual acknowledgement
//       properties:
//         isolation.level: read_committed

// ============ PRODUCER ============
@Service
public class OrderEventProducer {
  private final KafkaTemplate<String, OrderEvent> kafka;

  public OrderEventProducer(KafkaTemplate<String, OrderEvent> kafka) { this.kafka = kafka; }

  public void publishOrderCreated(Order order) {
    // Key = userId  →  all events for one user go to the SAME partition = strictly ordered.
    var event = new OrderEvent(order.getId(), order.getUserId(), "CREATED", order.getTotal(), Instant.now());
    kafka.send("orders", String.valueOf(order.getUserId()), event)
        .whenComplete((result, ex) -> {
          if (ex != null) log.error("Kafka send failed", ex);
          else log.info("Sent to partition {} offset {}",
              result.getRecordMetadata().partition(),
              result.getRecordMetadata().offset());
        });
  }
}

// ============ CONSUMER ============
@Component
public class OrderEventConsumer {
  private final BillingService billing;

  public OrderEventConsumer(BillingService billing) { this.billing = billing; }

  @KafkaListener(topics = "orders", groupId = "billing-service", containerFactory = "kafkaListenerContainerFactory")
  public void consume(ConsumerRecord<String, OrderEvent> record, Acknowledgment ack) {
    var event = record.value();
    try {
      // Idempotent — safe if Kafka redelivers.
      billing.processOrder(event);
      ack.acknowledge();   // commit offset ONLY on success
    } catch (RetryableException e) {
      // Don't ack; let Kafka redeliver after the retry timeout.
      log.warn("Retryable failure processing order {}", event.orderId(), e);
    } catch (Exception e) {
      // Send to a dead-letter topic so processing can continue.
      deadLetterTemplate.send("orders.dlt", record.key(), event);
      ack.acknowledge();   // committed — permanently skipped in main flow
    }
  }
}

// ============ IDEMPOTENCY on the consumer side ============
@Service
public class BillingService {
  private final BillingRepository repo;
  private final RedisTemplate<String, String> redis;

  public void processOrder(OrderEvent event) {
    // Idempotency key: (topic, offset) or event-provided idempotency-id.
    // Redis SET NX prevents double-charging on redelivery.
    var key = "processed:orders:" + event.orderId();
    var acquired = redis.opsForValue().setIfAbsent(key, "1", Duration.ofDays(7));
    if (Boolean.FALSE.equals(acquired)) {
      log.info("Already processed order {}", event.orderId());
      return;
    }
    // ... actually charge the card, save to DB, etc.
    repo.save(new BillingRecord(event));
  }
}

// Rule: assume at-least-once delivery. Make consumers IDEMPOTENT.
// Kafka retries + your code's idempotency = effective-exactly-once, robustly.
